public int maxAliveYear(int[][] logs) {
    int[] years = new int[2051];

    for(int[] log : logs) {
        years[log[0]]++;
        years[log[1]]--;
    }

    int max_population = 0;
    int max_year = 0;
    int population = 0;
    for(int i = 1950; i < 2051; i++) {
        population += years[i];
        if(population > max_population) {
            max_population = population;
            max_year = i;
        }
    }

    return max_year;
}
```


